{"content":"680: func (s *DiscoveryServer) pushConnection(con *Connection, pushEv *Event) error {
681: 	pushRequest := pushEv.pushRequest
682: 
683: 	if pushRequest.Full {
684: 		// Update Proxy with current information.
685: 		s.updateProxy(con.proxy, pushRequest)
686: 	}
687: 
688: 	if !s.ProxyNeedsPush(con.proxy, pushRequest) {
689: 		log.Debugf("Skipping push to %v, no updates required", con.conID)
690: 		if pushRequest.Full {
691: 			// Only report for full versions, incremental pushes do not have a new version.
692: 			reportAllEvents(s.StatusReporter, con.conID, pushRequest.Push.LedgerVersion, nil)
693: 		}
694: 		return nil
695: 	}
696: 
697: 	// Send pushes to all generators
698: 	// Each Generator is responsible for determining if the push event requires a push
699: 	wrl, ignoreEvents := con.pushDetails()
700: 	for _, w := range wrl {
701: 		if err := s.pushXds(con, w, pushRequest); err != nil {
702: 			return err
703: 		}
704: 	}
705: 	if pushRequest.Full {
706: 		// Report all events for unwatched resources. Watched resources will be reported in pushXds or on ack.
707: 		reportAllEvents(s.StatusReporter, con.conID, pushRequest.Push.LedgerVersion, ignoreEvents)
708: 	}
709: 
710: 	proxiesConvergeDelay.Record(time.Since(pushRequest.Start).Seconds())
